import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'vex_key' });

async function verifyVoiceResponse(response: string, conversationHistory: string[]): Promise<boolean> {
  const start = performance.now();

  const result = await vex.verify({
    prompt: 'voice agent conversation',
    response,
    metadata: {
      latencyBudget: 500,
      history: conversationHistory.slice(-10), // Last 10 turns
      checks: ['appropriateness', 'coherence', 'safety']
    }
  });

  const verificationTime = performance.now() - start;

  if (verificationTime > 100) {
    console.warn('Vex verification exceeded latency budget');
    return false;
  }

  return result.passed;
}
